const body = $input.first().json.body || $input.first().json;
const message    = body.message    || '';
const session_id = body.session_id || '';
const ticket_id  = Math.random().toString(36).slice(2, 8).toUpperCase();
const customer   = body.customer   || 'Web User';
const timestamp  = new Date().toISOString();
return [{ json: { message, session_id, ticket_id, customer, timestamp } }];

