const prev = $('Prepare Data').first().json;
const aiNode = $input.first().json;
const raw = aiNode.output || aiNode.text || aiNode.message || aiNode.response || aiNode.choices?.[0]?.message?.content || '';
const noThink = raw.replace(/<think>[\s\S]*?<\/think>/gi, '').trim();
const cleaned = noThink.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();
let ai = { kb_match: 'no', classification: 'out_of_scope', confidence_score: 0, draft_reply: '' };
try { ai = JSON.parse(cleaned); } catch(e) {
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) { try { ai = JSON.parse(match[0]); } catch(e2) {} }
}
const answerable = ai.kb_match === 'yes' || (ai.classification !== 'out_of_scope' && (ai.confidence_score || 0) >= 0.5);
return [{ json: {
  message:          prev.message,
  session_id:       prev.session_id,
  ticket_id:        prev.ticket_id,
  customer:         prev.customer,
  timestamp:        prev.timestamp,
  answerable:       answerable,
  draft_reply:      ai.draft_reply || '',
  classification:   ai.classification || 'out_of_scope',
  confidence_score: ai.confidence_score || 0,
  marketing_flag:   ai.marketing_flag || 'no',
  marketing_signal: ai.marketing_signal || null
} }];

